// Customer.java - Entidad documentada
package com.paymentchange.customer.entities;

import io.swagger.v3.oas.annotations.media.Schema;
import jakarta.persistence.*;
import lombok.Data;
import java.util.ArrayList;
import java.util.List;

@Data
@Entity
@Schema(description = "Modelo de Customer que representa un cliente del sistema financiero")
public class Customer {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    @Schema(
        description = "ID único del cliente",
        example = "1",
        accessMode = Schema.AccessMode.READ_ONLY
    )
    private Long id;

    @Schema(
        description = "Nombre completo del cliente",
        example = "Juan Pérez García",
        required = true,
        minLength = 3,
        maxLength = 100
    )
    private String name;

    @Schema(
        description = "Número de teléfono del cliente",
        example = "+52-555-1234-5678",
        required = true,
        pattern = "^\\+?[0-9-]+$"
    )
    private String phoneNumber;

    @Schema(
        description = "Correo electrónico del cliente",
        example = "juan.perez@email.com",
        format = "email"
    )
    private String email;

    @Schema(
        description = "Estado del cliente en el sistema",
        example = "ACTIVE",
        allowableValues = {"ACTIVE", "INACTIVE", "SUSPENDED"}
    )
    private String status;

    @ElementCollection
    @CollectionTable(
        name = "customer_products",
        joinColumns = @JoinColumn(name = "customer_id")
    )
    @Column(name = "product_id")
    @Schema(
        description = "IDs de productos asociados al cliente",
        example = "[1, 2, 3]"
    )
    private List<Long> productIds = new ArrayList<>();
}
